func resourceCESEvaluationRead(d *schema.ResourceData, meta interface{}) error {
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}

	url, err := tpgresource.ReplaceVars(d, config, "{{CESBasePath}}projects/{{project}}/locations/{{location}}/apps/{{app}}/evaluations/{{name}}")
	if err != nil {
		return err
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Evaluation: %s", err)
	}
	billingProject = project

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	headers := make(http.Header)
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "GET",
		Project:   billingProject,
		RawURL:    url,
		UserAgent: userAgent,
		Headers:   headers,
	})
	if err != nil {
		return transport_tpg.HandleNotFoundError(err, d, fmt.Sprintf("CESEvaluation %q", d.Id()))
	}

	log.Printf("[DEBUG] Finished reading CESEvaluation %q: %#v", d.Id(), res)

	if err := d.Set("project", project); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}

	if err := d.Set("name", flattenCESEvaluationName(res["name"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("display_name", flattenCESEvaluationDisplayName(res["displayName"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("description", flattenCESEvaluationDescription(res["description"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("tags", flattenCESEvaluationTags(res["tags"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("evaluation_datasets", flattenCESEvaluationEvaluationDatasets(res["evaluationDatasets"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("create_time", flattenCESEvaluationCreateTime(res["createTime"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("created_by", flattenCESEvaluationCreatedBy(res["createdBy"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("update_time", flattenCESEvaluationUpdateTime(res["updateTime"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("last_updated_by", flattenCESEvaluationLastUpdatedBy(res["lastUpdatedBy"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("evaluation_runs", flattenCESEvaluationEvaluationRuns(res["evaluationRuns"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("etag", flattenCESEvaluationEtag(res["etag"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("invalid", flattenCESEvaluationInvalid(res["invalid"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("golden", flattenCESEvaluationGolden(res["golden"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}
	if err := d.Set("scenario", flattenCESEvaluationScenario(res["scenario"], d, config)); err != nil {
		return fmt.Errorf("Error reading Evaluation: %s", err)
	}

	identity, err := d.Identity()
	if err == nil && identity != nil {
		if v, ok := identity.GetOk("name"); !ok && v == "" {
			err = identity.Set("name", d.Get("name").(string))
			if err != nil {
				return fmt.Errorf("Error setting name: %s", err)
			}
		}
		if v, ok := identity.GetOk("location"); !ok && v == "" {
			err = identity.Set("location", d.Get("location").(string))
			if err != nil {
				return fmt.Errorf("Error setting location: %s", err)
			}
		}
		if v, ok := identity.GetOk("app"); !ok && v == "" {
			err = identity.Set("app", d.Get("app").(string))
			if err != nil {
				return fmt.Errorf("Error setting app: %s", err)
			}
		}
		if v, ok := identity.GetOk("project"); !ok && v == "" {
			err = identity.Set("project", d.Get("project").(string))
			if err != nil {
				return fmt.Errorf("Error setting project: %s", err)
			}
		}
	} else {
		log.Printf("[DEBUG] (Read) identity not set: %s", err)
	}

	return nil
}

func resourceCESEvaluationUpdate(d *schema.ResourceData, meta interface{}) error {
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}
	identity, err := d.Identity()
	if err == nil && identity != nil {
		if nameValue, ok := d.GetOk("name"); ok && nameValue.(string) != "" {
			if err = identity.Set("name", nameValue.(string)); err != nil {
				return fmt.Errorf("Error setting name: %s", err)
			}
		}
		if locationValue, ok := d.GetOk("location"); ok && locationValue.(string) != "" {
			if err = identity.Set("location", locationValue.(string)); err != nil {
				return fmt.Errorf("Error setting location: %s", err)
			}
		}
		if appValue, ok := d.GetOk("app"); ok && appValue.(string) != "" {
			if err = identity.Set("app", appValue.(string)); err != nil {
				return fmt.Errorf("Error setting app: %s", err)
			}
		}
		if projectValue, ok := d.GetOk("project"); ok && projectValue.(string) != "" {
			if err = identity.Set("project", projectValue.(string)); err != nil {
				return fmt.Errorf("Error setting project: %s", err)
			}
		}
	} else {
		log.Printf("[DEBUG] (Update) identity not set: %s", err)
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Evaluation: %s", err)
	}
	billingProject = project

	obj := make(map[string]interface{})
	displayNameProp, err := expandCESEvaluationDisplayName(d.Get("display_name"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("display_name"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, displayNameProp)) {
		obj["displayName"] = displayNameProp
	}
	descriptionProp, err := expandCESEvaluationDescription(d.Get("description"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("description"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, descriptionProp)) {
		obj["description"] = descriptionProp
	}
	tagsProp, err := expandCESEvaluationTags(d.Get("tags"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("tags"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, tagsProp)) {
		obj["tags"] = tagsProp
	}
	goldenProp, err := expandCESEvaluationGolden(d.Get("golden"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("golden"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, goldenProp)) {
		obj["golden"] = goldenProp
	}
	scenarioProp, err := expandCESEvaluationScenario(d.Get("scenario"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("scenario"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, scenarioProp)) {
		obj["scenario"] = scenarioProp
	}

	url, err := tpgresource.ReplaceVars(d, config, "{{CESBasePath}}projects/{{project}}/locations/{{location}}/apps/{{app}}/evaluations/{{name}}")
	if err != nil {
		return err
	}

	log.Printf("[DEBUG] Updating Evaluation %q: %#v", d.Id(), obj)
	headers := make(http.Header)
	updateMask := []string{}

	if d.HasChange("display_name") {
		updateMask = append(updateMask, "displayName")
	}

	if d.HasChange("description") {
		updateMask = append(updateMask, "description")
	}

	if d.HasChange("tags") {
		updateMask = append(updateMask, "tags")
	}

	if d.HasChange("golden") {
		updateMask = append(updateMask, "golden")
	}

	if d.HasChange("scenario") {
		updateMask = append(updateMask, "scenario")
	}
	// updateMask is a URL parameter but not present in the schema, so ReplaceVars
	// won't set it
	url, err = transport_tpg.AddQueryParams(url, map[string]string{"updateMask": strings.Join(updateMask, ",")})
	if err != nil {
		return err
	}

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	// if updateMask is empty we are not updating anything so skip the post
	if len(updateMask) > 0 {
		res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "PATCH",
			Project:   billingProject,
			RawURL:    url,
			UserAgent: userAgent,
			Body:      obj,
			Timeout:   d.Timeout(schema.TimeoutUpdate),
			Headers:   headers,
		})

		if err != nil {
			return fmt.Errorf("Error updating Evaluation %q: %s", d.Id(), err)
		} else {
			log.Printf("[DEBUG] Finished updating Evaluation %q: %#v", d.Id(), res)
		}

	}

	return resourceCESEvaluationRead(d, meta)
}

